interface PaymentMethod {
  boolean pay(double amount);
}

class CreditCardPayment implements PaymentMethod {
  @Override
  public boolean pay(double amount) {
    return amount > 0;
  }
}

class Checkout {
  void complete(PaymentMethod method, double total) {
    if (!method.pay(total)) {
      throw new IllegalStateException("payment failed");
    }
  }
}

class Checkout {
  void complete(CreditCardPayment method, double total) {
    method.pay(total);
  }
}
